   159→/// Arguments for vvx_emplace command
   160→#[derive(clap::Args, Debug)]
   161→struct EmplaceArgs {
   162→    /// Extracted parcel directory (contains vvbf_brand.json, kits/)
   163→    #[arg(long)]
   164→    parcel: PathBuf,
   165→
   166→    /// Path to target repo's burc.env file
   167→    #[arg(long)]
   168→    burc: PathBuf,
   169→}
   170→
   171→/// Arguments for vvx_vacate command
   172→#[derive(clap::Args, Debug)]
   173→struct VacateArgs {
   174→    /// Path to target repo's burc.env file
   175→    #[arg(long)]
   176→    burc: PathBuf,
   177→}
   178→
   179→/// Arguments for vvx_freshen command
   180→#[derive(clap::Args, Debug)]
   181→struct FreshenArgs {
   182→    /// Path to burc.env file (resolves project_root and tools_dir)
   183→    #[arg(long)]
   184→    burc: PathBuf,
   185→}
   186→
   187→#[tokio::main]
   188→async fn main() -> ExitCode {
   189→    let cli = Cli::parse();
   190→
   191→    let exit_code = match cli.command {
   192→        Some(Commands::Guard(args)) => run_guard(args),
   193→        Some(Commands::VvxCommit(args)) => run_commit(args),
   194→        Some(Commands::VvxInvitatory) => run_invitatory().await,
   195→        Some(Commands::VvxPush(args)) => run_push(args),
   196→        Some(Commands::VvxUnlock) => run_unlock(),
   197→        Some(Commands::ReleaseCollect(args)) => run_release_collect(args),
   198→        Some(Commands::ReleaseBrand(args)) => run_release_brand(args),
   199→        Some(Commands::VvxEmplace(args)) => run_emplace(args),
   200→        Some(Commands::VvxVacate(args)) => run_vacate(args),
   201→        Some(Commands::VvxFreshen(args)) => run_freshen(args),
   202→        Some(Commands::External(args)) => dispatch_external(args).await,
   203→        None => {
   204→            use clap::CommandFactory;
   205→            Cli::command().print_help().ok();
   206→            0
   207→        }
   208→    };
   209→
   210→    ExitCode::from(exit_code as u8)
   211→}
