   213→/// Run guard command using vvc
   214→fn run_guard(args: GuardArgs) -> i32 {
   215→    let vvc_args = vvc::vvcg_GuardArgs {
   216→        limit: args.limit,
   217→        warn: args.warn,
   218→    };
   219→    vvc::guard(&vvc_args, None)
   220→}
   221→
   222→/// Run commit command using vvc
   223→fn run_commit(args: CommitArgs) -> i32 {
   224→    let vvc_args = vvc::vvcc_CommitArgs {
   225→        prefix: args.prefix,
   226→        message: args.message,
   227→        allow_empty: args.allow_empty,
   228→        no_stage: args.no_stage,
   229→        size_limit: vvc::VVCG_SIZE_LIMIT,
   230→        warn_limit: vvc::VVCG_WARN_LIMIT,
   231→    };
   232→    vvc::commit(&vvc_args)
   233→}
   234→
   235→/// Run invitatory command using vvc
   236→async fn run_invitatory() -> i32 {
   237→    match vvc::vvcp_invitatory().await {
   238→        Ok(()) => 0,
   239→        Err(e) => {
   240→            eprintln!("invitatory: error: {}", e);
   241→            1
   242→        }
   243→    }
   244→}
