   400→/// Run release_collect command
   401→fn run_release_collect(args: ReleaseCollectArgs) -> i32 {
   402→    eprintln!("release_collect: collecting assets...");
   403→    eprintln!("  staging: {}", args.staging.display());
   404→    eprintln!("  tools_dir: {}", args.tools_dir.display());
