   406→
   407→    // Parse comma-separated kit list
   408→    let managed_kits: Vec<String> = args.managed_kits
   409→        .split(',')
   410→        .map(|s| s.trim().to_string())
   411→        .filter(|s| !s.is_empty())
   412→        .collect();
   413→
   414→    match vof::vofr_collect(&args.tools_dir, &args.staging, &args.install_script, &managed_kits) {
   415→        Ok(result) => {
   416→            // Output JSON for bash to parse
   417→            let mut output = serde_json::Map::new();
   418→            output.insert("total_files".to_string(), serde_json::Value::Number(result.total_files.into()));
   419→            output.insert("commands_routed".to_string(), serde_json::Value::Number(result.commands_routed.into()));
   420→
   421→            let kit_counts: serde_json::Map<String, serde_json::Value> = result.kit_counts
   422→                .into_iter()
   423→                .map(|(k, v)| (k, serde_json::Value::Number(v.into())))
   424→                .collect();
   425→            output.insert("kit_counts".to_string(), serde_json::Value::Object(kit_counts));
   426→
   427→            println!("{}", serde_json::to_string_pretty(&serde_json::Value::Object(output)).unwrap());
   428→            eprintln!("release_collect: success - {} files collected", result.total_files);
   429→            0
   430→        }
   431→        Err(e) => {
   432→            eprintln!("release_collect: error: {}", e);
   433→            1
   434→        }
   435→    }
   436→}
